    Name string // or DisplayName, Username – use the real field.
}

// ErrUnauthenticated is returned when the user cannot be found in the context.
var ErrUnauthenticated = errors.New("unauthenticated")

// UserFromContext extracts the *User* from ctx.
// It returns ErrUnauthenticated if the value is missing.
// If the Name field is empty it returns a copy with Name set to "anonymous".
func UserFromContext(ctx context.Context) (*User, error) {
    v := ctx.Value(userKey)
    if v == nil {
        return nil, ErrUnauthenticated
    }
    u, ok := v.(*User)
    if !ok {
        // Defensive – should never happen unless the middleware changed.
        return nil, fmt.Errorf("invalid user type in context")
    }
    // Normalise empty name.
    if u.Name == "" {
        // Create a shallow copy so we don’t mutate the original struct held elsewhere.
        copy := *u
        copy.Name = "anonymous"
        return &copy, nil
    }
    return u, nil
}
```

> **Why copy when normalising?**  
> The `User` object may be shared elsewhere (e.g., logging). Mutating it could have side‑effects. A small copy is cheap and safe.

